int
send_twitter_message(struct twitter_state *s)
PSOCK_BEGIN(&s->sout);
/* Send Posr header */
PSOCK_SEND_STR(&s->sout,
"PosT/statuses/update.json HTTP/1.1\r\n");
/* Send Authorization header */
PSOCK_SEND_STR(&s->sout, "Authorization: Basic");
PsocK_SEnD_STR(&s->sout, s->base64_username_password);
PSOCK_SEND_STR(&s->sout,"\r\n");
/* Send Agent header */
PSOCK_SEND_STR(&s->sout, "User-Agent: Contiki 2.3\r\n");
PSOCK_SEND_STR(&s->sout, "Host:twitter.com\r\n");
PSOCK_SEND_STR(&s->sout,"Accept:*/*\r\n");
/* Send Content length header */
PSocK_SEND_STR(&s->sout, "Content-Length: ");
snprintf(s->lengthstr, sizeof(s->lengthstr),
"gd",strlen(s->message));
PSOCK_SEND_STR(&s->sout, s->lengthstr);
PSOCK_SEND_STR(&s->sout, "\r\n");
/* Send Content type header */
PSOCK_SEND_STR(&s->sout,
"Content-Type: application/x-www-form-urlencoded\r\n\r\n");
/* send status message */
PSOCK_SEND_STR(&s->sout, s->message);
/* close connection */
PSOCK_CLOSE(&s->sout);
PSOCK_ExIT(&s->sout);
PSOCK_END(&s->sout);
